import java.util.HashMap;
import java.util.Map;

public class Solution {
    public static String bestPokerHand(int[] ranks, char[] suits) {
        Map<Integer, Integer> rankCount = new HashMap<>();
        Map<Character, Integer> suitCount = new HashMap<>();
        for (int i = 0; i < ranks.length; i++) {
            rankCount.put(ranks[i], rankCount.getOrDefault(ranks[i], 0) + 1);
            suitCount.put(suits[i], suitCount.getOrDefault(suits[i], 0) + 1);
        }
        if (suitCount.size() == 1) return "Flush ";
        if (rankCount.size() == 3) return "Three of a Kind ";
        for (Map.Entry<Integer, Integer> entry : rankCount.entrySet()) {
            if (entry.getValue() == 2) return "Pair ";
        }
        return "High Card ";
    }
}
```


